import { createPortal } from 'react-dom'
import { useEffect, useState } from 'react'
import { FALLBACK_LABEL_COLOR, FONT_FAMILY } from './constants'
import type { LabelDef, Pin } from './types'

interface Props {
  pin: Pin
  num: number
  label?: LabelDef
  layerId: string
  isSelected: boolean
  isHovered?: boolean
  onSelect: () => void
  onMove: (pos: { x: number; y: number }) => void
  onHoverEnter: (id: string) => void
  onHoverLeave: (id: string) => void
}

function timeAgo(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime()
  if (diff < 60_000) return '방금'
  if (diff < 3_600_000) return `${Math.floor(diff / 60_000)}분 전`
  if (diff < 86_400_000) return `${Math.floor(diff / 3_600_000)}시간 전`
  return `${Math.floor(diff / 86_400_000)}일 전`
}

// ── 인라인 마크다운 렌더러 ──────────────────────────────────────
function renderInlineMarkdown(text: string): React.ReactNode[] {
  const lines = text.split('\n')
  const nodes: React.ReactNode[] = []

  lines.forEach((rawLine, lineIdx) => {
    const line = rawLine
      .replace(/^#{1,6}\s+/, '')
      .replace(/^```.*/, '')
      .replace(/^>\s?/, '')
      .replace(/^[-*+]\s+/, '')

    const inline: React.ReactNode[] = []
    const regex = /(\*\*(.+?)\*\*|\*(.+?)\*|`(.+?)`)/g
    let last = 0
    let m: RegExpExecArray | null
    let k = 0

    while ((m = regex.exec(line)) !== null) {
      if (m.index > last) inline.push(line.slice(last, m.index))
      if (m[0].startsWith('**')) {
        inline.push(
          <strong key={k++} style={{ fontWeight: 700, color: 'rgba(255,255,255,.8)' }}>
            {m[2]}
          </strong>
        )
      } else if (m[0].startsWith('*')) {
        inline.push(<em key={k++}>{m[3]}</em>)
      } else {
        inline.push(
          <code
            key={k++}
            style={{
              fontFamily: 'monospace',
              background: 'rgba(255,255,255,.12)',
              padding: '0 3px',
              borderRadius: 3,
              fontSize: 9,
            }}
          >
            {m[4]}
          </code>
        )
      }
      last = m.index + m[0].length
    }
    if (last < line.length) inline.push(line.slice(last))

    nodes.push(...inline)
    if (lineIdx < lines.length - 1) nodes.push(<br key={`br-${lineIdx}`} />)
  })

  return nodes
}

const EXPAND_W = 220

export function AnnotPin({
  pin,
  num,
  label,
  layerId,
  isSelected,
  isHovered,
  onSelect,
  onMove,
  onHoverEnter,
  onHoverLeave,
}: Props) {
  const color = label?.color ?? FALLBACK_LABEL_COLOR
  const isResolved = pin.status === 'resolved'
  const emphasized = isSelected || isHovered

  const expanded = !isSelected && !!isHovered
  const hasNote = !!pin.note
  const hasComments = pin.comments.length > 0

  // 뷰포트 좌표 — 포털 버블 위치 및 확장 방향 계산에만 사용
  // 핀 배지 위치는 CSS % 로 처리하여 resize 시 브라우저가 직접 계산 (드리프트 없음)
  const { viewportX, viewportY, expandLeft } = (() => {
    const el = document.getElementById(layerId)
    const r = el?.getBoundingClientRect() ?? { left: 0, top: 0, width: window.innerWidth, height: window.innerHeight }
    const vx = r.left + pin.x * r.width
    const vy = r.top + pin.y * r.height
    return {
      viewportX: vx,
      viewportY: vy,
      expandLeft: expanded && vx + EXPAND_W > window.innerWidth - 8,
    }
  })()

  const EDGE = 8
  const MIN_UP = 120
  const expandDown = expanded && (viewportY + 28 - EDGE) < MIN_UP
  const maxExpandH = expanded
    ? (expandDown
        ? Math.min(400, window.innerHeight - viewportY - EDGE)
        : Math.min(400, viewportY + 28 - EDGE))
    : 28

  // 확장 콘텐츠 페이드 애니메이션
  const [contentReady, setContentReady] = useState(false)
  useEffect(() => {
    if (!expanded) { setContentReady(false); return }
    const raf = requestAnimationFrame(() => setContentReady(true))
    return () => cancelAnimationFrame(raf)
  }, [expanded])

  // 드래그: 선택 상태일 때만
  const onMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0) return
    if (!isSelected) {
      e.stopPropagation()
      onSelect()
      return
    }
    e.stopPropagation()

    const container = document.getElementById(layerId)
    if (!container) return
    const base = container.getBoundingClientRect()

    let moved = false
    const startX = e.clientX - base.left - pin.x * base.width
    const startY = e.clientY - base.top - pin.y * base.height

    const onMoveHandler = (ev: MouseEvent) => {
      moved = true
      const newPx = ev.clientX - base.left - startX
      const newPy = ev.clientY - base.top - startY
      onMove({
        x: Math.max(0, Math.min(1, newPx / base.width)),
        y: Math.max(0, Math.min(1, newPy / base.height)),
      })
    }
    const onUp = () => {
      document.removeEventListener('mousemove', onMoveHandler)
      document.removeEventListener('mouseup', onUp)
      if (!moved) onSelect()
    }
    document.addEventListener('mousemove', onMoveHandler)
    document.addEventListener('mouseup', onUp)
  }

  // 포털 버블 위치 (position:fixed, 뷰포트 기준)
  // expandLeft=false → 핀 왼쪽에서 오른쪽으로 확장
  // expandLeft=true  → 핀 오른쪽에서 왼쪽으로 확장
  const portalLeft = expandLeft ? viewportX - (EXPAND_W - 28) : viewportX
  const portalVertical: React.CSSProperties = expandDown
    ? { top: viewportY }
    : { bottom: window.innerHeight - viewportY - 28 }

  const expandedBorderRadius = '16px 16px 16px 4px'

  // 배지 원형 (소형 핀 & 포털 버블 공용)
  const Badge = (
    <div
      style={{
        width: 22,
        height: 22,
        borderRadius: '50%',
        background: color,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexShrink: 0,
      }}
    >
      <span style={{ color: '#fff', fontSize: 10, fontWeight: 700, lineHeight: 1 }}>
        {num}
      </span>
    </div>
  )

  return (
    <>
      {/* ── 핀 배지 — 항상 28×28, position:absolute (overflow:hidden 에 클리핑되지 않는 범위) ── */}
      <div
        onMouseDown={onMouseDown}
        onMouseEnter={() => onHoverEnter(pin.id)}
        onMouseLeave={() => onHoverLeave(pin.id)}
        style={{
          position: 'absolute',
          left: `${pin.x * 100}%`,
          top: `${pin.y * 100}%`,
          width: 28,
          height: 28,
          borderRadius: '80px 80px 80px 12px',
          background: '#1A1A1A',
          boxShadow: isSelected
            ? `0 0 0 2.5px ${isResolved ? '#6b7280' : color}, 0 0 0 4.5px rgba(255,255,255,.8), 0 4px 14px rgba(0,0,0,.38)`
            : '0 2px 8px rgba(0,0,0,.28)',
          cursor: isSelected ? 'grab' : 'pointer',
          userSelect: 'none',
          opacity: isResolved && !emphasized ? 0.4 : 1,
          filter: isResolved && !emphasized ? 'grayscale(1)' : 'none',
          zIndex: isSelected ? 9993 : isHovered ? 9992 : 9991,
          fontFamily: FONT_FAMILY,
          pointerEvents: 'all',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          boxSizing: 'border-box',
        }}
      >
        {Badge}
      </div>

      {/* ── 호버 확장 버블 — createPortal → body, position:fixed ──
           overflow:hidden 에 잘리지 않고 뷰포트 어디서나 표시 */}
      {expanded && typeof document !== 'undefined' && createPortal(
        <div
          onMouseDown={onMouseDown}
          onMouseEnter={() => onHoverEnter(pin.id)}
          onMouseLeave={() => onHoverLeave(pin.id)}
          style={{
            position: 'fixed',
            left: portalLeft,
            ...portalVertical,
            width: EXPAND_W,
            maxHeight: maxExpandH,
            minHeight: 28,
            borderRadius: expandedBorderRadius,
            background: '#1A1A1A',
            boxShadow: '0 6px 18px rgba(0,0,0,.38)',
            cursor: 'pointer',
            userSelect: 'none',
            opacity: isResolved && !emphasized ? 0.4 : 1,
            filter: isResolved && !emphasized ? 'grayscale(1)' : 'none',
            zIndex: 9992,
            fontFamily: FONT_FAMILY,
            pointerEvents: 'all',
            display: 'flex',
            flexDirection: expandLeft ? 'row-reverse' : 'row',
            alignItems: 'flex-start',
            overflow: 'hidden',
            padding: '8px',
            boxSizing: 'border-box',
          }}
        >
          {Badge}
          <div
            style={{
              flex: 1,
              minWidth: 0,
              paddingLeft: expandLeft ? 0 : 7,
              paddingRight: expandLeft ? 7 : 0,
              display: 'flex',
              flexDirection: 'column',
              gap: 3,
              opacity: contentReady ? 1 : 0,
              transform: contentReady ? 'none' : `translateX(${expandLeft ? 5 : -5}px)`,
              transition: 'opacity 0.32s ease-out, transform 0.32s ease-out',
            }}
          >
            {/* 1행: 작성자 · 시간 + [해결 배지 — 오른쪽 상단] */}
            <div style={{ display: 'flex', alignItems: 'center', gap: 5, minWidth: 0 }}>
              <span
                style={{
                  fontSize: 10,
                  color: 'rgba(255,255,255,.75)',
                  fontWeight: 600,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  flexShrink: 1,
                  minWidth: 0,
                }}
              >
                {pin.author || '—'}
              </span>
              <span
                style={{
                  fontSize: 9,
                  color: 'rgba(255,255,255,.3)',
                  flexShrink: 0,
                  whiteSpace: 'nowrap',
                }}
              >
                {timeAgo(pin.createdAt)}
              </span>
              {/* 해결 배지 — 오른쪽 상단 */}
              {isResolved && (
                <span
                  style={{
                    marginLeft: 'auto',
                    flexShrink: 0,
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: 2,
                    padding: '1px 5px',
                    borderRadius: 2,
                    background: 'rgba(22,163,74,.22)',
                    border: '1px solid rgba(22,163,74,.4)',
                    color: '#4ade80',
                    fontSize: 8,
                    fontWeight: 700,
                    whiteSpace: 'nowrap',
                  }}
                >
                  ✓ 해결
                </span>
              )}
            </div>

            {/* 2행: 노트 미리보기 */}
            {hasNote && (
              <div
                style={{
                  fontSize: 10,
                  color: 'rgba(255,255,255,.5)',
                  lineHeight: 1.5,
                  overflow: 'hidden',
                  display: '-webkit-box',
                  WebkitLineClamp: 10,
                  WebkitBoxOrient: 'vertical',
                  wordBreak: 'break-word',
                }}
              >
                {renderInlineMarkdown(pin.note!)}
              </div>
            )}

            {/* 3행: 댓글 수 */}
            {hasComments && (
              <>
                <div style={{ height: 1, background: 'rgba(255,255,255,.08)', margin: '2px 0' }} />
                <div style={{ display: 'flex', alignItems: 'center', gap: 5, color: 'rgba(255,255,255,.45)' }}>
                  <svg width="11" height="11" viewBox="0 0 16 16" fill="none" style={{ color: '#93c5fd' }}>
                    <path d="M13 1H3C2.45 1 2 1.45 2 2v8c0 .55.45 1 1 1h2.5l2.5 3 2.5-3H13c.55 0 1-.45 1-1V2c0-.55-.45-1-1-1z" fill="currentColor"/>
                  </svg>
                  <span style={{ fontSize: 9, fontWeight: 600, color: 'rgba(255,255,255,.55)' }}>
                    {pin.comments.length}
                  </span>
                </div>
              </>
            )}
          </div>
        </div>,
        document.body
      )}
    </>
  )
}
