import { useState, useEffect } from 'react'
import { COLORS as C, DARK, LABEL_COLOR_PRESETS } from './constants'
import type { LabelDef } from './types'

interface Props {
  labels: LabelDef[]
  pinUsage: Record<string, number>
  onAdd: (name: string, color: string) => void | Promise<unknown>
  onUpdate: (id: string, patch: Partial<Omit<LabelDef, 'id'>>) => void | Promise<void>
  onDelete: (id: string) => void | Promise<void>
  onClose: () => void
}

export function LabelManagerModal({ labels, pinUsage, onAdd, onUpdate, onDelete, onClose }: Props) {
  const [newName, setNewName] = useState('')
  const [newColor, setNewColor] = useState(LABEL_COLOR_PRESETS[0])

  const handleAdd = () => {
    const name = newName.trim()
    if (!name) return
    onAdd(name, newColor)
    setNewName('')
    setNewColor(LABEL_COLOR_PRESETS[0])
  }

  const inp: React.CSSProperties = {
    padding: '7px 10px',
    border: `1px solid ${DARK.brd2}`,
    borderRadius: 6,
    fontSize: 12,
    outline: 'none',
    boxSizing: 'border-box',
    fontFamily: 'inherit',
    background: DARK.bg3,
    color: DARK.txt,
  }

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.stopPropagation()
        onClose()
      }
    }
    window.addEventListener('keydown', handler, true)
    return () => window.removeEventListener('keydown', handler, true)
  }, [onClose])

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 11000,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'rgba(0,0,0,.55)',
      }}
      onClick={onClose}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: DARK.bg,
          border: `1px solid ${DARK.brd}`,
          borderRadius: 14,
          width: 440,
          maxHeight: '80vh',
          display: 'flex',
          flexDirection: 'column',
          boxShadow: '0 20px 60px rgba(0,0,0,.5)',
          overflow: 'hidden',
        }}
      >
        {/* 헤더 */}
        <div
          style={{
            padding: '14px 18px',
            background: DARK.bg2,
            borderBottom: `1px solid ${DARK.brd}`,
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            flexShrink: 0,
          }}
        >
          <div>
            <div style={{ fontSize: 13, fontWeight: 700, color: DARK.txt }}>🏷️ 레이블 관리</div>
            <div style={{ fontSize: 10, color: DARK.txL, marginTop: 2 }}>
              전체 페이지에 공통 적용됩니다
            </div>
          </div>
          <button
            onClick={onClose}
            style={{
              background: 'rgba(255,255,255,.08)',
              border: 'none',
              color: DARK.txS,
              width: 28,
              height: 28,
              borderRadius: 6,
              cursor: 'pointer',
              fontSize: 16,
            }}
          >
            ×
          </button>
        </div>

        {/* 목록 */}
        <div className="sb-scroll" style={{ flex: 1, overflowY: 'auto', padding: '14px 18px' }}>
          {labels.length === 0 ? (
            <div style={{ padding: '24px 0', textAlign: 'center', color: DARK.txL, fontSize: 12 }}>
              등록된 레이블이 없습니다. 아래에서 추가하세요.
            </div>
          ) : (
            labels.map((label) => (
              <LabelRow
                key={label.id}
                label={label}
                usage={pinUsage[label.id] ?? 0}
                onUpdate={(patch) => onUpdate(label.id, patch)}
                onDelete={() => onDelete(label.id)}
              />
            ))
          )}
        </div>

        {/* 추가 */}
        <div
          style={{
            borderTop: `1px solid ${DARK.brd}`,
            padding: '12px 18px',
            background: DARK.bg2,
            flexShrink: 0,
          }}
        >
          <div style={{ fontSize: 11, fontWeight: 600, color: DARK.txS, marginBottom: 6 }}>
            + 레이블 추가
          </div>
          <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
            <ColorDot color={newColor} onChange={setNewColor} title="색상 선택" />
            <input
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter') handleAdd() }}
              placeholder="레이블 이름 (예: UI 이슈)"
              style={{ ...inp, flex: 1 }}
            />
            <button
              onClick={handleAdd}
              disabled={!newName.trim()}
              style={{
                padding: '7px 14px',
                border: 'none',
                borderRadius: 6,
                background: newName.trim() ? C.pri : DARK.bg3,
                color: newName.trim() ? '#fff' : DARK.txL,
                fontSize: 12,
                fontWeight: 600,
                cursor: newName.trim() ? 'pointer' : 'not-allowed',
              }}
            >
              추가
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

interface LabelRowProps {
  label: LabelDef
  usage: number
  onUpdate: (patch: Partial<Omit<LabelDef, 'id'>>) => void
  onDelete: () => void
}

function LabelRow({ label, usage, onUpdate, onDelete }: LabelRowProps) {
  const [editing, setEditing] = useState(false)
  const [draftName, setDraftName] = useState(label.name)

  const commit = () => {
    const n = draftName.trim()
    if (n && n !== label.name) onUpdate({ name: n })
    else setDraftName(label.name)
    setEditing(false)
  }

  const handleDelete = () => {
    if (usage > 0) {
      const ok = window.confirm(
        `이 레이블을 사용 중인 핀이 ${usage}개 있습니다.\n삭제하면 해당 핀들은 "미분류"로 표시됩니다. 계속할까요?`
      )
      if (!ok) return
    }
    onDelete()
  }

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 8,
        padding: '8px 6px',
        borderBottom: `1px solid ${DARK.brd}`,
      }}
    >
      <ColorDot color={label.color} onChange={(c) => onUpdate({ color: c })} title="색상 변경" />
      {editing ? (
        <input
          autoFocus
          value={draftName}
          onChange={(e) => setDraftName(e.target.value)}
          onBlur={commit}
          onKeyDown={(e) => {
            if (e.key === 'Enter') commit()
            if (e.key === 'Escape') { setDraftName(label.name); setEditing(false) }
          }}
          style={{
            flex: 1,
            padding: '4px 8px',
            border: `1px solid ${DARK.brd2}`,
            borderRadius: 5,
            fontSize: 12,
            outline: 'none',
            fontFamily: 'inherit',
            background: DARK.bg3,
            color: DARK.txt,
          }}
        />
      ) : (
        <div
          onClick={() => setEditing(true)}
          style={{ flex: 1, fontSize: 13, fontWeight: 500, color: DARK.txt, cursor: 'text', padding: '4px 2px' }}
          title="클릭하여 수정"
        >
          {label.name}
        </div>
      )}
      <span style={{ fontSize: 10, color: usage > 0 ? DARK.txS : DARK.txL, minWidth: 40, textAlign: 'right' }}>
        {usage}개 사용
      </span>
      <button
        onClick={handleDelete}
        title="레이블 삭제"
        style={{
          padding: '4px 8px',
          border: `1px solid ${DARK.brd}`,
          borderRadius: 5,
          background: 'transparent',
          color: '#f87171',
          fontSize: 11,
          cursor: 'pointer',
        }}
      >
        삭제
      </button>
    </div>
  )
}

interface ColorDotProps {
  color: string
  onChange: (color: string) => void
  title?: string
}

function ColorDot({ color, onChange, title }: ColorDotProps) {
  const [open, setOpen] = useState(false)
  return (
    <div style={{ position: 'relative' }}>
      <button
        onClick={() => setOpen((v) => !v)}
        title={title}
        style={{
          width: 22,
          height: 22,
          borderRadius: 5,
          background: color,
          border: `1px solid ${DARK.brd}`,
          cursor: 'pointer',
          padding: 0,
          flexShrink: 0,
        }}
      />
      {open && (
        <>
          <div onClick={() => setOpen(false)} style={{ position: 'fixed', inset: 0, zIndex: 1 }} />
          <div
            style={{
              position: 'absolute',
              top: 26,
              left: 0,
              zIndex: 2,
              background: DARK.bg2,
              border: `1px solid ${DARK.brd}`,
              borderRadius: 7,
              padding: 8,
              boxShadow: '0 8px 24px rgba(0,0,0,.4)',
              display: 'grid',
              gridTemplateColumns: 'repeat(4, 22px)',
              gap: 6,
            }}
          >
            {LABEL_COLOR_PRESETS.map((c) => (
              <button
                key={c}
                onClick={() => { onChange(c); setOpen(false) }}
                style={{
                  width: 22,
                  height: 22,
                  borderRadius: 4,
                  background: c,
                  border: c === color ? `2px solid #fff` : `1px solid ${DARK.brd}`,
                  cursor: 'pointer',
                  padding: 0,
                }}
              />
            ))}
          </div>
        </>
      )}
    </div>
  )
}
