interface TBtnProps {
  icon: ReactNode
  label?: string
  active?: boolean
  activeColor?: string
  badge?: number
  disabled?: boolean
  onClick: () => void
  title: string
  dataGuide?: string
}

function TBtn({ icon, label, active, activeColor = '#3B82F6', badge, disabled, onClick, title, dataGuide }: TBtnProps) {
  return (
    <button
      onClick={onClick}
      title={title}
      disabled={disabled}
      data-guide={dataGuide}
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: label ? 3 : 0,
        padding: '5px 8px',
        border: `1px solid ${active ? `${activeColor}66` : 'rgba(255,255,255,.07)'}`,
        borderRadius: 2,
        cursor: disabled ? 'not-allowed' : 'pointer',
        background: active ? `${activeColor}25` : 'transparent',
        color: disabled
          ? 'rgba(255,255,255,.2)'
          : active
          ? activeColor
          : 'rgba(255,255,255,.7)',
        transition: 'all .15s',
        flexShrink: 0,
        opacity: disabled ? 0.4 : 1,
        minWidth: 26,
        height: 26,
        fontFamily: FONT_FAMILY,
      }}
      onMouseEnter={(e) => {
        if (!active && !disabled) {
          e.currentTarget.style.background = 'rgba(255,255,255,.07)'
          e.currentTarget.style.color = 'rgba(255,255,255,1)'
          e.currentTarget.style.borderColor = 'rgba(255,255,255,.15)'
        }
      }}
      onMouseLeave={(e) => {
        if (!active && !disabled) {
          e.currentTarget.style.background = 'transparent'
          e.currentTarget.style.color = 'rgba(255,255,255,.7)'
          e.currentTarget.style.borderColor = 'rgba(255,255,255,.07)'
        }
      }}
    >
      {icon}
      {label && <span style={{ fontSize: 11, fontWeight: 500, whiteSpace: 'nowrap' }}>{label}</span>}
      {badge != null && badge > 0 && (
        <span
          style={{
            minWidth: 14,
            height: 14,
            borderRadius: 3,
            background: active ? 'rgba(255,255,255,.25)' : 'rgba(255,255,255,.18)',
            color: '#fff',
            fontSize: 9,
            fontWeight: 700,
            display: 'inline-flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '0 3px',
            flexShrink: 0,
          }}
        >
          {badge}
        </span>
      )}
    </button>
  )
}

/** v0.7.11 → v0.7011 (major.minor + patch 3자리) */
function shortVer(v: string): string {
  const [major = '0', minor = '0', patch = '0'] = v.replace(/^v/, '').split('.')
  return `v${major}.${minor}${patch.padStart(3, '0')}`
}

/** semver 단순 비교: a > b → true */
function isNewer(a: string | null, b: string): boolean {
  if (!a) return false
  const parse = (v: string) => v.replace(/^v/, '').split('.').map(Number)
  const [ma, mi, pa] = parse(a)
  const [mb, mi2, pb] = parse(b)
  if (ma !== mb) return ma > mb
  if (mi !== mi2) return mi > mi2
  return pa > pb
}

/** 업데이트 안내 모달 */
function UpdateModal({
  currentVersion,
  latestVersion,
  onClose,
}: {
  currentVersion: string
  latestVersion: string
  onClose: () => void
}) {
  const [copied, setCopied] = useState<string | null>(null)
  const copyCmd = (cmd: string) => {
    navigator.clipboard.writeText(cmd).catch(() => {})
    setCopied(cmd)
    setTimeout(() => setCopied(null), 2000)
  }
  const gitCmd = `pnpm add git+https://github.com/knowsol/specBridge.git#v${latestVersion}`
  const npmCmd = `npm install git+https://github.com/knowsol/specBridge.git#v${latestVersion}`

  return (
    <div
      onClick={onClose}
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(0,0,0,.55)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 20000,
        fontFamily: FONT_FAMILY,
      }}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: '#0f172a',
          border: '1px solid rgba(251,191,36,.3)',
          borderRadius: 4,
          padding: 28,
          width: 460,
          boxShadow: '0 24px 64px rgba(0,0,0,.6)',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 18 }}>
          <div>
            <div style={{ fontSize: 15, fontWeight: 700, color: '#fbbf24', marginBottom: 4 }}>
              🚀 새 버전 업데이트 안내
            </div>
            <div style={{ fontSize: 12, color: 'rgba(255,255,255,.5)' }}>
              현재&nbsp;
              <span style={{ fontFamily: 'monospace', color: 'rgba(255,255,255,.75)' }}>v{currentVersion}</span>
              &nbsp;→&nbsp;최신&nbsp;
              <span style={{ fontFamily: 'monospace', color: '#34d399', fontWeight: 700 }}>v{latestVersion}</span>
            </div>
          </div>
          <button
            onClick={onClose}
            style={{ background: 'transparent', border: 'none', color: 'rgba(255,255,255,.4)', fontSize: 18, cursor: 'pointer', padding: '0 4px' }}
          >✕</button>
        </div>
        <div style={{ fontSize: 11, color: 'rgba(255,255,255,.4)', marginBottom: 8 }}>
          아래 명령어로 업그레이드 후 앱을 재배포하세요:
        </div>
        {[{ label: 'pnpm', cmd: gitCmd }, { label: 'npm', cmd: npmCmd }].map(({ label, cmd }) => (
          <div key={label} style={{ background: '#1e293b', borderRadius: 4, padding: '10px 12px', marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8, border: '1px solid rgba(255,255,255,.06)' }}>
            <span style={{ fontSize: 9, fontWeight: 700, color: '#64748b', width: 30, flexShrink: 0, textTransform: 'uppercase' }}>{label}</span>
            <code style={{ flex: 1, fontSize: 11, color: '#a5f3fc', fontFamily: 'monospace', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{cmd}</code>
            <button
              onClick={() => copyCmd(cmd)}
              style={{ background: copied === cmd ? '#16a34a' : 'rgba(255,255,255,.07)', border: 'none', borderRadius: 2, color: copied === cmd ? '#fff' : 'rgba(255,255,255,.5)', fontSize: 10, padding: '4px 8px', cursor: 'pointer', flexShrink: 0, transition: 'all .15s' }}
            >{copied === cmd ? '✓ 복사됨' : '복사'}</button>
          </div>
        ))}
        <div style={{ fontSize: 10, color: 'rgba(255,255,255,.25)', marginTop: 12 }}>
          업그레이드 후 SDK를 재빌드하고 앱을 재배포해야 적용됩니다.
        </div>
      </div>
    </div>
  )
}

