const VIEWPORT_ICON: Record<string, React.ReactNode> = {
  desktop: <IDesktop />,
  tablet:  <ITablet />,
  mobile:  <IMobile />,
}

function SessionPickerItem({
  session,
  isActive,
  progress,
  onClick,
  onDelete,
  onStatusChange,
  onEdit,
}: {
  session: AnnotSession
  isActive: boolean
  progress?: { total: number; resolved: number }
  onClick: () => void
  onDelete: (e: React.MouseEvent) => void
  onStatusChange?: (status: SessionStatus) => void
  onEdit?: (name: string, viewport: SessionViewport | null) => Promise<void>
}) {
  const [hov, setHov] = useState(false)
  const [confirming, setConfirming] = useState(false)
  const [editing, setEditing] = useState(false)
  const [editName, setEditName] = useState('')
  const [editViewport, setEditViewport] = useState<SessionViewport | null>(null)

  const startEdit = (e: React.MouseEvent) => {
    e.stopPropagation()
    setEditName(session.name)
    setEditViewport(session.viewport ?? null)
    setConfirming(false)
    setEditing(true)
  }
  const cancelEdit = (e: React.MouseEvent) => { e.stopPropagation(); setEditing(false) }
  const saveEdit = async (e: React.MouseEvent) => {
    e.stopPropagation()
    const trimmed = editName.trim()
    if (!trimmed || !onEdit) { setEditing(false); return }
    await onEdit(trimmed, editViewport)
    setEditing(false)
  }

  const status = session.status ?? 'active'
  const sc = SESSION_STATUS_CONFIG[status]
  const vp = session.viewport ? SESSION_VIEWPORT_CONFIG[session.viewport] : null
  const pct = progress && progress.total > 0 ? Math.round((progress.resolved / progress.total) * 100) : 0

  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => { if (!editing) { setHov(false); setConfirming(false) } }}
      style={{
        padding: '8px 12px',
        cursor: 'pointer',
        background: isActive ? 'rgba(255,255,255,.07)' : hov ? 'rgba(255,255,255,.04)' : 'transparent',
        transition: 'background .12s',
      }}
    >
      {/* 상단 행: 뷰포트 아이콘 + 이름 + 상태 배지 + 삭제 */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
        <span style={{ fontSize: 10, color: isActive ? 'rgba(255,255,255,.5)' : 'rgba(255,255,255,.18)', flexShrink: 0, width: 12, textAlign: 'center' }}>
          {isActive ? '✓' : ''}
        </span>
        {vp && (
          <span style={{ color: 'rgba(255,255,255,.45)', flexShrink: 0, display: 'flex', alignItems: 'center' }} title={vp.label}>
            {VIEWPORT_ICON[session.viewport ?? ''] ?? null}
          </span>
        )}
        <span style={{ flex: 1, fontSize: 12, color: isActive ? 'rgba(255,255,255,.88)' : 'rgba(255,255,255,.55)', fontWeight: isActive ? 600 : 400, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontFamily: FONT_FAMILY }}>
          {session.name}
        </span>
        {/* 상태 배지 — 클릭하면 순환 */}
        <button
          onClick={(e) => {
            e.stopPropagation()
            if (!onStatusChange) return
            const idx = STATUS_CYCLE.indexOf(status)
            onStatusChange(STATUS_CYCLE[(idx + 1) % STATUS_CYCLE.length])
          }}
          title="상태 변경 (클릭)"
          style={{
            background: sc.bg, border: `1px solid ${sc.border}`,
            borderRadius: 2, color: sc.color,
            fontSize: 9, fontWeight: 700,
            padding: '2px 6px', cursor: 'pointer',
            flexShrink: 0, fontFamily: FONT_FAMILY,
            transition: 'all .12s',
          }}
        >{sc.label}</button>
        {hov && !confirming && !editing && onEdit && (
          <button
            onClick={startEdit}
            title="회차 수정"
            style={{ background: 'transparent', border: '1px solid rgba(255,255,255,.12)', borderRadius: 2, color: 'rgba(255,255,255,.3)', fontSize: 9, padding: '2px 5px', cursor: 'pointer', flexShrink: 0, fontFamily: FONT_FAMILY, transition: 'all .12s', display: 'flex', alignItems: 'center' }}
            onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(255,255,255,.08)'; e.currentTarget.style.borderColor = 'rgba(255,255,255,.3)'; e.currentTarget.style.color = 'rgba(255,255,255,.7)' }}
            onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.borderColor = 'rgba(255,255,255,.12)'; e.currentTarget.style.color = 'rgba(255,255,255,.3)' }}
          ><IEdit /></button>
        )}
        {hov && !confirming && !editing && (
          <button
            onClick={(e) => { e.stopPropagation(); setConfirming(true) }}
            title="회차 삭제"
            style={{ background: 'transparent', border: '1px solid rgba(255,255,255,.12)', borderRadius: 2, color: 'rgba(255,255,255,.3)', fontSize: 9, padding: '2px 5px', cursor: 'pointer', flexShrink: 0, fontFamily: FONT_FAMILY, transition: 'all .12s' }}
            onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(220,38,38,.15)'; e.currentTarget.style.borderColor = 'rgba(220,38,38,.3)'; e.currentTarget.style.color = '#f87171' }}
            onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.borderColor = 'rgba(255,255,255,.12)'; e.currentTarget.style.color = 'rgba(255,255,255,.3)' }}
          >삭제</button>
        )}
        {confirming && (
          <div onClick={(e) => e.stopPropagation()} style={{ display: 'flex', gap: 4, alignItems: 'center', flexShrink: 0 }}>
            <span style={{ fontSize: 9, color: '#f87171', fontFamily: FONT_FAMILY, whiteSpace: 'nowrap' }}>삭제할까요?</span>
            <button
              onClick={(e) => { e.stopPropagation(); setConfirming(false) }}
              style={{ background: 'transparent', border: '1px solid rgba(255,255,255,.15)', borderRadius: 2, color: 'rgba(255,255,255,.45)', fontSize: 9, padding: '2px 6px', cursor: 'pointer', fontFamily: FONT_FAMILY }}
            >취소</button>
            <button
              onClick={onDelete}
              style={{ background: 'rgba(220,38,38,.2)', border: '1px solid rgba(220,38,38,.4)', borderRadius: 2, color: '#f87171', fontSize: 9, fontWeight: 700, padding: '2px 6px', cursor: 'pointer', fontFamily: FONT_FAMILY }}
            >확인</button>
          </div>
        )}
      </div>
      {/* 하단 행: 진행률 */}
      {progress && progress.total > 0 && (
        <div style={{ marginTop: 6, paddingLeft: 18 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}>
            <div style={{ flex: 1, height: 3, background: 'rgba(255,255,255,.18)', borderRadius: 2, overflow: 'hidden' }}>
              <div style={{ width: `${pct}%`, height: '100%', background: pct === 100 ? '#16a34a' : C.pri, borderRadius: 2, transition: 'width .3s' }} />
            </div>
            <span style={{ fontSize: 9, color: 'rgba(255,255,255,.3)', flexShrink: 0, fontFamily: FONT_FAMILY }}>
              {progress.resolved}/{progress.total}
            </span>
          </div>
        </div>
      )}

      {/* 인라인 편집 폼 */}
      {editing && (
        <div onClick={(e) => e.stopPropagation()} style={{ marginTop: 8, paddingLeft: 18 }}>
          <input
            autoFocus
            value={editName}
            onChange={(e) => setEditName(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') saveEdit(e as unknown as React.MouseEvent); if (e.key === 'Escape') { e.stopPropagation(); setEditing(false) } }}
            style={{
              width: '100%', boxSizing: 'border-box',
              background: 'rgba(255,255,255,.07)', border: '1px solid rgba(255,255,255,.18)',
              borderRadius: 2, padding: '4px 7px',
              color: '#fff', fontSize: 11, fontFamily: FONT_FAMILY, outline: 'none',
              marginBottom: 6,
            }}
          />
          <div style={{ display: 'flex', gap: 4, marginBottom: 6 }}>
            {(Object.entries(SESSION_VIEWPORT_CONFIG) as [SessionViewport, { label: string; icon: string }][]).map(([vp, cfg]) => {
              const isVpActive = editViewport === vp
              return (
                <button
                  key={vp}
                  onClick={(e) => { e.stopPropagation(); setEditViewport(isVpActive ? null : vp) }}
                  style={{
                    flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 3,
                    padding: '3px 0', borderRadius: 2,
                    border: `1px solid ${isVpActive ? 'rgba(255,255,255,.3)' : 'rgba(255,255,255,.18)'}`,
                    background: isVpActive ? 'rgba(255,255,255,.12)' : 'transparent',
                    color: isVpActive ? 'rgba(255,255,255,.85)' : 'rgba(255,255,255,.3)',
                    fontSize: 10, cursor: 'pointer', fontFamily: FONT_FAMILY, transition: 'all .12s',
                  }}
                >
                  <span style={{ display: 'flex', alignItems: 'center' }}>{VIEWPORT_ICON[vp]}</span>
                  <span>{cfg.label}</span>
                </button>
              )
            })}
          </div>
          <div style={{ display: 'flex', gap: 5 }}>
            <button
              onClick={cancelEdit}
              style={{ flex: 1, background: 'transparent', border: '1px solid rgba(255,255,255,.1)', borderRadius: 2, color: 'rgba(255,255,255,.4)', fontSize: 11, padding: '3px 0', cursor: 'pointer', fontFamily: FONT_FAMILY }}
            >취소</button>
            <button
              onClick={saveEdit}
              style={{ flex: 2, background: C.pri, border: 'none', borderRadius: 2, color: '#fff', fontSize: 11, fontWeight: 600, padding: '3px 0', cursor: 'pointer', fontFamily: FONT_FAMILY }}
            >저장</button>
          </div>
        </div>
      )}
    </div>
  )
}

function SessionPicker({
  sessions,
  currentSessionId,
  sessionProgress,
  onSelectSession,
  onCreateSession,
  onDeleteSession,
  onSetSessionStatus,
  onUpdateSession,
}: {
  sessions: AnnotSession[]
  currentSessionId: string | null
  sessionProgress?: Record<string, { total: number; resolved: number }>
  onSelectSession: (id: string | null) => void
  onCreateSession: (name: string, options?: { viewport?: SessionViewport | null }) => Promise<string | null>
  onDeleteSession: (id: string) => Promise<void>
  onSetSessionStatus?: (id: string, status: SessionStatus) => Promise<void>
  onUpdateSession?: (id: string, patch: Partial<Pick<AnnotSession, 'name' | 'status' | 'viewport' | 'note'>>) => Promise<void>
}) {
  const [open, setOpen] = useState(false)
  const [creating, setCreating] = useState(false)
  const [newName, setNewName] = useState('')
  const [newViewport, setNewViewport] = useState<SessionViewport | null>(null)
  const ref = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!open) return
    const handler = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false)
        setCreating(false)
        setNewName('')
        setNewViewport(null)
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [open])

  const currentSession = sessions.find((s) => s.id === currentSessionId)
  const triggerLabel = currentSession ? currentSession.name : '전체'
  const triggerVp = currentSession?.viewport ? SESSION_VIEWPORT_CONFIG[currentSession.viewport] : null

  const handleCreate = async () => {
    const trimmed = newName.trim()
    if (!trimmed) return
    await onCreateSession(trimmed, { viewport: newViewport })
    setNewName('')
    setNewViewport(null)
    setCreating(false)
    setOpen(false)
  }

  return (
    <div ref={ref} style={{ position: 'relative', flexShrink: 0 }}>
      {/* 트리거 버튼 */}
      <button
        onClick={() => setOpen((v) => !v)}
        title="검토 회차 선택"
        data-guide="sb-session"
        style={{
          display: 'flex', alignItems: 'center', gap: 3,
          padding: '5px 8px', borderRadius: 2,
          border: '1px solid rgba(255,255,255,.07)',
          background: open ? 'rgba(255,255,255,.07)' : 'transparent',
          color: 'rgba(255,255,255,.7)', fontSize: 11, fontWeight: 500,
          cursor: 'pointer', height: 26, fontFamily: FONT_FAMILY,
          whiteSpace: 'nowrap', maxWidth: 160, transition: 'all .15s',
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = 'rgba(255,255,255,.07)'
          e.currentTarget.style.color = 'rgba(255,255,255,1)'
          e.currentTarget.style.borderColor = 'rgba(255,255,255,.15)'
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = open ? 'rgba(255,255,255,.07)' : 'transparent'
          e.currentTarget.style.color = 'rgba(255,255,255,.7)'
          e.currentTarget.style.borderColor = 'rgba(255,255,255,.07)'
        }}
      >
        <span style={{ color: 'rgba(255,255,255,.6)', display: 'flex', alignItems: 'center' }}>
          {triggerVp ? VIEWPORT_ICON[currentSession?.viewport ?? ''] : <IBookmark />}
        </span>
        <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', maxWidth: 110 }}>{triggerLabel}</span>
        <span style={{ fontSize: 8, opacity: 0.6, marginLeft: 1 }}>▾</span>
      </button>

      {/* 드롭다운 */}
      {open && (
        <div
          style={{
            position: 'absolute', bottom: 'calc(100% + 8px)', left: 0,
            minWidth: 260,
            background: 'rgba(10,10,10,.97)',
            backdropFilter: 'blur(24px)', WebkitBackdropFilter: 'blur(24px)',
            border: '1px solid rgba(255,255,255,.07)', borderRadius: 4,
            boxShadow: '0 -8px 40px rgba(0,0,0,.6)',
            overflow: 'hidden', zIndex: 20000, fontFamily: FONT_FAMILY,
          }}
        >
          {/* 헤더 */}
          <div style={{ padding: '8px 12px 6px', fontSize: 10, fontWeight: 700, color: 'rgba(255,255,255,.3)', letterSpacing: '.5px', textTransform: 'uppercase' }}>
            검토 회차
          </div>
          <div style={{ height: 1, background: 'rgba(255,255,255,.07)' }} />

          {/* 전체 옵션 */}
          <div
            onClick={() => { onSelectSession(null); setOpen(false) }}
            style={{
              display: 'flex', alignItems: 'center', gap: 8, padding: '8px 12px',
              cursor: 'pointer',
              background: currentSessionId === null ? 'rgba(255,255,255,.07)' : 'transparent',
              transition: 'background .12s',
            }}
            onMouseEnter={(e) => { if (currentSessionId !== null) e.currentTarget.style.background = 'rgba(255,255,255,.04)' }}
            onMouseLeave={(e) => { if (currentSessionId !== null) e.currentTarget.style.background = 'transparent' }}
          >
            <span style={{ fontSize: 10, color: currentSessionId === null ? 'rgba(255,255,255,.5)' : 'transparent', width: 12, textAlign: 'center', flexShrink: 0 }}>✓</span>
            <span style={{ fontSize: 12, color: currentSessionId === null ? 'rgba(255,255,255,.88)' : 'rgba(255,255,255,.45)', fontWeight: currentSessionId === null ? 600 : 400, fontFamily: FONT_FAMILY }}>
              전체 (모든 회차)
            </span>
          </div>

          {sessions.length > 0 && (
            <div style={{ height: 1, background: 'rgba(255,255,255,.06)', margin: '2px 0' }} />
          )}

          {sessions.map((s) => (
            <SessionPickerItem
              key={s.id}
              session={s}
              isActive={s.id === currentSessionId}
              progress={sessionProgress?.[s.id]}
              onClick={() => { onSelectSession(s.id); setOpen(false) }}
              onDelete={(e) => { e.stopPropagation(); onDeleteSession(s.id) }}
              onStatusChange={onSetSessionStatus ? (st) => onSetSessionStatus(s.id, st) : undefined}
              onEdit={onUpdateSession ? (name, viewport) => onUpdateSession(s.id, { name, viewport }) : undefined}
            />
          ))}

          <div style={{ height: 1, background: 'rgba(255,255,255,.07)', margin: '2px 0' }} />

          {/* 새 회차 만들기 */}
          {creating ? (
            <div style={{ padding: '8px 10px' }}>
              <input
                // eslint-disable-next-line jsx-a11y/no-autofocus
                autoFocus
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') { e.preventDefault(); handleCreate() }
                  if (e.key === 'Escape') { setCreating(false); setNewName(''); setNewViewport(null) }
                }}
                placeholder="회차 이름 입력…"
                style={{
                  width: '100%', boxSizing: 'border-box',
                  background: 'rgba(255,255,255,.07)', border: '1px solid rgba(255,255,255,.18)',
                  borderRadius: 2, padding: '5px 8px',
                  color: '#fff', fontSize: 11, fontFamily: FONT_FAMILY, outline: 'none',
                  marginBottom: 7,
                }}
              />
              {/* 뷰포트 선택 */}
              <div style={{ display: 'flex', gap: 4, marginBottom: 8 }}>
                {(Object.entries(SESSION_VIEWPORT_CONFIG) as [SessionViewport, { label: string; icon: string }][]).map(([vp, cfg]) => {
                  const isVpActive = newViewport === vp
                  return (
                    <button
                      key={vp}
                      onClick={() => setNewViewport(isVpActive ? null : vp)}
                      style={{
                        flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4,
                        padding: '4px 0', borderRadius: 2,
                        border: `1px solid ${isVpActive ? 'rgba(255,255,255,.3)' : 'rgba(255,255,255,.18)'}`,
                        background: isVpActive ? 'rgba(255,255,255,.12)' : 'transparent',
                        color: isVpActive ? 'rgba(255,255,255,.85)' : 'rgba(255,255,255,.3)',
                        fontSize: 10, cursor: 'pointer', fontFamily: FONT_FAMILY,
                        transition: 'all .12s',
                      }}
                    >
                      <span style={{ display: 'flex', alignItems: 'center' }}>{VIEWPORT_ICON[vp]}</span>
                      <span>{cfg.label}</span>
                    </button>
                  )
                })}
              </div>
              <div style={{ display: 'flex', gap: 6 }}>
                <button
                  onClick={() => { setCreating(false); setNewName(''); setNewViewport(null) }}
                  style={{ flex: 1, background: 'transparent', border: '1px solid rgba(255,255,255,.1)', borderRadius: 2, color: 'rgba(255,255,255,.4)', fontSize: 11, padding: '4px 0', cursor: 'pointer', fontFamily: FONT_FAMILY }}
                >취소</button>
                <button
                  onClick={handleCreate}
                  style={{ flex: 2, background: C.pri, border: 'none', borderRadius: 2, color: '#fff', fontSize: 11, padding: '4px 0', cursor: 'pointer', fontFamily: FONT_FAMILY, fontWeight: 600 }}
                >추가</button>
              </div>
            </div>
          ) : (
            <button
              onClick={() => setCreating(true)}
              style={{
                width: '100%', display: 'flex', alignItems: 'center', gap: 7,
                padding: '8px 12px', background: 'transparent', border: 'none',
                color: 'rgba(255,255,255,.38)', fontSize: 11, cursor: 'pointer',
                textAlign: 'left', fontFamily: FONT_FAMILY, transition: 'all .12s',
              }}
              onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(255,255,255,.05)'; e.currentTarget.style.color = 'rgba(255,255,255,.7)' }}
              onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'rgba(255,255,255,.38)' }}
            >
              <span style={{ fontSize: 13 }}>＋</span>
              <span>새 검토 회차</span>
            </button>
          )}
        </div>
      )}
    </div>
  )
}

// ── SpecBridge 로고 인라인 SVG (viewBox 확장 — 클리핑 없음) ──────────────────
function SBLogo({ size = 28 }: { size?: number }) {
  return (
    <svg width={size} height={size} viewBox="-10 -10 170 172" fill="none" style={{ display: 'block', flexShrink: 0 }}>
      <path opacity="0.69" d="M111.309 79.6218C116.002 96.9372 100.191 112.84 82.8489 108.247L21.3533 91.961C4.01096 87.3681 -1.85607 65.7239 10.7927 53.0015L55.6448 7.88791C68.2936 -4.83456 89.9715 0.906559 94.6651 18.2219L111.309 79.6218Z" fill="#3078FF"/>
      <path opacity="0.5" d="M101.327 142.828C86.0562 152.245 66.3188 141.599 65.7993 123.666L64.723 86.5136C64.2035 68.5809 83.2915 56.8106 99.0814 65.3271L131.795 82.9713C147.585 91.4877 148.234 113.904 132.964 123.32L101.327 142.828Z" fill="#4CD3FF"/>
    </svg>
  )
}

export function AnnotationToolbar({
  enabled,
  onToggleEnabled,
  author,
  onEditAuthor,
  adding,
  onToggleAdd,
  pinCount,
  showList,
  onToggleList,
  onExport,
  labels,
  filterLabelIds,
  onToggleLabelFilter,
  onClearLabelFilter,
  latestSdkVersion,
  onShowGuide,
  showLogoTip,
  sessions,
  currentSessionId,
  sessionProgress,
  onSelectSession,
  onCreateSession,
  onDeleteSession,
  onSetSessionStatus,
  onUpdateSession,
}: Props) {
  const [showUpdateModal, setShowUpdateModal] = useState(false)
  const hasUpdate = isNewer(latestSdkVersion ?? null, SDK_VERSION)

  return (
    <div style={{ position: 'fixed', bottom: 0, left: 0, right: 0, zIndex: 10000, fontFamily: FONT_FAMILY }}>
      {/* 배치 중 힌트 */}
      {enabled && adding && (
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 6, pointerEvents: 'none' }}>
          <div
            style={{
              background: 'rgba(180,83,9,.95)',
              backdropFilter: 'blur(8px)',
              borderRadius: 20,
              padding: '6px 18px',
              fontSize: 12,
              color: '#fef3c7',
              fontWeight: 500,
              boxShadow: '0 4px 16px rgba(0,0,0,.3)',
              border: '1px solid rgba(251,191,36,.3)',
              animation: 'specbridgeTbHint .15s ease',
            }}
          >
            📌 화면 아무 곳이나 클릭하면 번호가 배치됩니다 — ESC / N / 취소 버튼으로 중단
          </div>
          <style>{`@keyframes specbridgeTbHint{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}`}</style>
        </div>
      )}

      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          background: 'rgba(0,0,0,0.9)',
          backdropFilter: 'blur(5px)',
          WebkitBackdropFilter: 'blur(5px)',
          borderTop: '1px solid rgba(255,255,255,0.07)',
          boxShadow: '0 -4px 24px rgba(0,0,0,.4)',
          height: 45,
          padding: '0 8px 0 16px',
          gap: 0,
        }}
      >
        {/* ── 왼쪽: 로고 (flex:1 → 중앙 기준 좌측 공간 균등) ── */}
        <div
          style={{
            flex: 1,
            display: 'flex',
            alignItems: 'center',
            gap: 7,
          }}
        >
          <div style={{ position: 'relative', flexShrink: 0 }}>
            <div
              onClick={onShowGuide}
              title="사용 가이드 보기"
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: onShowGuide ? 'pointer' : 'default',
                transition: 'opacity .15s',
              }}
              onMouseEnter={(e) => { if (onShowGuide) e.currentTarget.style.opacity = '.72' }}
              onMouseLeave={(e) => { e.currentTarget.style.opacity = '1' }}
            >
              <SBLogo size={28} />
            </div>
            {showLogoTip && (
              <div
                style={{
                  position: 'absolute',
                  bottom: 'calc(100% + 10px)',
                  left: '50%',
                  transform: 'translateX(-50%)',
                  background: 'rgba(10,10,10,.97)',
                  border: '1px solid rgba(255,255,255,.15)',
                  borderRadius: 4,
                  padding: '8px 12px',
                  fontSize: 11,
                  color: 'rgba(255,255,255,.82)',
                  whiteSpace: 'nowrap',
                  boxShadow: '0 8px 24px rgba(0,0,0,.55)',
                  pointerEvents: 'none',
                  zIndex: 20001,
                  fontFamily: FONT_FAMILY,
                  lineHeight: 1.5,
                }}
              >
                로고를 클릭하면 가이드를 다시 볼 수 있어요 👆
                <div
                  style={{
                    position: 'absolute',
                    bottom: -5,
                    left: '50%',
                    transform: 'translateX(-50%) rotate(45deg)',
                    width: 8,
                    height: 8,
                    background: 'rgba(10,10,10,.97)',
                    borderRight: '1px solid rgba(255,255,255,.15)',
                    borderBottom: '1px solid rgba(255,255,255,.15)',
                  }}
                />
              </div>
            )}
          </div>
          <button
            onClick={hasUpdate ? () => setShowUpdateModal(true) : undefined}
            title={hasUpdate ? `업데이트 가능: ${shortVer(latestSdkVersion ?? '')} — 클릭하여 안내 보기` : `SpecBridge SDK ${shortVer(SDK_VERSION)}`}
            style={{ background: 'transparent', border: 'none', padding: 0, cursor: hasUpdate ? 'pointer' : 'default', display: 'flex', flexDirection: 'column', alignItems: 'flex-start', gap: 3 }}
          >
            <span style={{ fontSize: 11, fontWeight: 700, color: 'rgba(255,255,255,.7)', letterSpacing: '.2px', lineHeight: 1, whiteSpace: 'nowrap' }}>
              SpecBridge
            </span>
            <div style={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <span style={{ fontSize: 9, fontWeight: 700, color: C.pri, lineHeight: 1 }}>Beta</span>
              <span style={{ fontSize: 9, fontFamily: 'monospace', color: hasUpdate ? '#fbbf24' : 'rgba(255,255,255,.55)', lineHeight: 1 }}>
                {shortVer(SDK_VERSION)}
              </span>
              {hasUpdate && (
                <span style={{ fontSize: 7, fontWeight: 700, background: '#f59e0b', color: '#0f172a', borderRadius: 3, padding: '1px 3px', lineHeight: 1.4, whiteSpace: 'nowrap' }}>
                  ↑ {shortVer(latestSdkVersion ?? '')}
                </span>
              )}
            </div>
          </button>

          {/* 검토 회차 선택기 */}
          {enabled && sessions && onSelectSession && onCreateSession && onDeleteSession && (
            <>
              <div style={{ width: 1, height: 22, background: 'rgba(255,255,255,.18)', flexShrink: 0, marginLeft: 4 }} />
              <SessionPicker
                sessions={sessions}
                currentSessionId={currentSessionId ?? null}
                sessionProgress={sessionProgress}
                onSelectSession={onSelectSession}
                onCreateSession={onCreateSession}
                onDeleteSession={onDeleteSession}
                onSetSessionStatus={onSetSessionStatus}
                onUpdateSession={onUpdateSession}
              />
            </>
          )}
        </div>

        {/* ── 중앙: 레이블 필터 ── */}
        <div data-guide="sb-label-filter" style={{ flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 3 }}>
          {enabled && labels && labels.length > 0 && (() => {
            const allActive = !filterLabelIds || filterLabelIds.size === 0
            return (
              <>
                {/* 전체 버튼 */}
                <button
                  onClick={onClearLabelFilter}
                  title="전체 보기"
                  style={{
                    display: 'flex', alignItems: 'center',
                    padding: '2px 10px',
                    borderRadius: 1,
                    border: `1px solid ${allActive ? 'rgba(255,255,255,.4)' : 'rgba(255,255,255,.15)'}`,
                    background: allActive ? 'rgba(255,255,255,.12)' : 'transparent',
                    color: allActive ? 'rgba(255,255,255,.9)' : 'rgba(255,255,255,.45)',
                    fontSize: 11, fontWeight: 500,
                    cursor: 'pointer', height: 20,
                    transition: 'all .15s', whiteSpace: 'nowrap',
                    flexShrink: 0, fontFamily: FONT_FAMILY,
                  }}
                  onMouseEnter={(e) => { if (!allActive) { e.currentTarget.style.borderColor = 'rgba(255,255,255,.3)'; e.currentTarget.style.color = 'rgba(255,255,255,.75)' } }}
                  onMouseLeave={(e) => { if (!allActive) { e.currentTarget.style.borderColor = 'rgba(255,255,255,.15)'; e.currentTarget.style.color = 'rgba(255,255,255,.45)' } }}
                >
                  전체
                </button>

                {/* 레이블 버튼들 */}
                {labels.map((l) => {
                  const active = filterLabelIds?.has(l.id) ?? false
                  const color = l.color || FALLBACK_LABEL_COLOR
                  return (
                    <button
                      key={l.id}
                      onClick={() => onToggleLabelFilter?.(l.id)}
                      title={active ? `${l.name} 필터 해제` : `${l.name}만 보기`}
                      style={{
                        display: 'flex', alignItems: 'center', gap: 4,
                        padding: '2px 10px',
                        borderRadius: 1,
                        border: `1px solid ${active ? `${color}99` : 'rgba(255,255,255,.15)'}`,
                        background: active ? `${color}22` : 'transparent',
                        color: active ? color : 'rgba(255,255,255,.45)',
                        fontSize: 11, fontWeight: 500,
                        cursor: 'pointer', height: 20,
                        transition: 'all .15s', whiteSpace: 'nowrap',
                        flexShrink: 0, fontFamily: FONT_FAMILY,
                      }}
                      onMouseEnter={(e) => { if (!active) { e.currentTarget.style.borderColor = `${color}66`; e.currentTarget.style.color = color } }}
                      onMouseLeave={(e) => { if (!active) { e.currentTarget.style.borderColor = 'rgba(255,255,255,.15)'; e.currentTarget.style.color = 'rgba(255,255,255,.45)' } }}
                    >
                      <span style={{ width: 5, height: 5, borderRadius: '50%', background: active ? color : 'rgba(255,255,255,.3)', flexShrink: 0 }} />
                      {l.name}
                    </button>
                  )
                })}
              </>
            )
          })()}
        </div>

        {/* ── 오른쪽: 액션 버튼들 (flex:1 + justifyContent:flex-end → 좌측과 동일 너비) ── */}
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: 3 }}>
          {enabled && (
            <>
              <TBtn
                icon={adding ? <IClose /> : <IPlus />}
                label={adding ? '취소' : '추가'}
                active={adding}
                activeColor={C.pri}
                onClick={onToggleAdd}
                title={adding ? '번호 배치 취소 (ESC)' : '번호 추가 — 단축키 N'}
                dataGuide="sb-add-pin"
              />
              <TBtn
                icon={<IList />}
                label="목록"
                active={showList}
                activeColor={C.pri}
                badge={pinCount}
                onClick={onToggleList}
                title="현재 페이지 번호 목록 — 단축키 L"
                dataGuide="sb-pin-list"
              />
              <TBtn
                icon={<IDownload />}
                label="JSON"
                onClick={onExport}
                title="전체 어노테이션 JSON 내보내기"
              />
            </>
          )}

          {/* Annotation 토글 */}
          <button
            onClick={onToggleEnabled}
            title={enabled ? 'Annotation 끄기 — 단축키 A' : 'Annotation 켜기 — 단축키 A'}
            data-guide="sb-annotation"
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 3,
              padding: '5px 8px',
              border: `1px solid ${enabled ? `${C.pri}66` : 'rgba(255,255,255,.07)'}`,
              borderRadius: 2,
              cursor: 'pointer',
              background: enabled ? `${C.pri}25` : 'transparent',
              color: enabled ? C.pri : 'rgba(255,255,255,.7)',
              fontSize: 11,
              fontWeight: 600,
              height: 26,
              transition: 'all .15s',
              whiteSpace: 'nowrap',
              flexShrink: 0,
              fontFamily: FONT_FAMILY,
            }}
          >
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ flexShrink: 0 }}>
              <path d="M20 10c0 6-8 12-8 12S4 16 4 10a8 8 0 0 1 16 0Z"/>
              <circle cx="12" cy="10" r="3"/>
            </svg>
            <span>Annotation</span>
          </button>

          {/* 작성자 버튼 */}
          <button
            onClick={onEditAuthor}
            title={author ? `작성자: ${author}` : '작성자 설정'}
            data-guide="sb-author"
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 3,
              padding: '5px 8px',
              borderRadius: 2,
              background: author ? 'transparent' : 'rgba(251,191,36,.15)',
              color: author ? 'rgba(255,255,255,.7)' : '#fbbf24',
              fontSize: 11,
              cursor: 'pointer',
              height: 26,
              border: author ? '1px solid rgba(255,255,255,.07)' : '1px solid rgba(251,191,36,.4)',
              maxWidth: 130,
              flexShrink: 0,
              transition: 'all .15s',
              fontFamily: FONT_FAMILY,
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = 'rgba(255,255,255,.07)'
              e.currentTarget.style.color = 'rgba(255,255,255,1)'
              e.currentTarget.style.borderColor = 'rgba(255,255,255,.15)'
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = author ? 'transparent' : 'rgba(251,191,36,.15)'
              e.currentTarget.style.color = author ? 'rgba(255,255,255,.7)' : '#fbbf24'
              e.currentTarget.style.borderColor = author ? 'rgba(255,255,255,.07)' : 'rgba(251,191,36,.4)'
            }}
          >
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ flexShrink: 0 }}>
              <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
              <circle cx="12" cy="7" r="4"/>
            </svg>
            {!author && (
              <span style={{ fontSize: 9, background: '#dc2626', color: '#fff', borderRadius: 3, padding: '1px 3px', flexShrink: 0, fontWeight: 700 }}>!</span>
            )}
          </button>
        </div>
      </div>

      {showUpdateModal && latestSdkVersion && (
        <UpdateModal
          currentVersion={SDK_VERSION}
          latestVersion={latestSdkVersion}
          onClose={() => setShowUpdateModal(false)}
        />
      )}
    </div>
  )
}
