import { useCallback, useEffect, useState } from 'react'
import type { AnnotSession, SessionStatus, SessionViewport, StorageAdapter } from './types'

export function useSessions(storage: StorageAdapter) {
  const [sessions, setSessions] = useState<AnnotSession[]>([])

  useEffect(() => {
    let cancelled = false
    storage
      .loadSessions()
      .then(async (v) => {
        if (cancelled) return
        if (v.length > 0) {
          setSessions(v)
        } else {
          // 세션이 없으면 기본 1차 검토 회차 자동 생성
          try {
            const session = await storage.createSession('1차 검토')
            if (!cancelled) setSessions([session])
          } catch {
            if (!cancelled) setSessions([])
          }
        }
      })
      .catch((e) => console.error('[specbridge] loadSessions failed', e))
    return () => { cancelled = true }
  }, [storage])

  const addSession = useCallback(
    async (
      name: string,
      options?: { viewport?: SessionViewport | null }
    ): Promise<AnnotSession | null> => {
      const trimmed = name.trim()
      if (!trimmed) return null
      try {
        const session = await storage.createSession(trimmed, options)
        setSessions((prev) => [...prev, session])
        return session
      } catch (e) {
        console.error('[specbridge] createSession failed', e)
        return null
      }
    },
    [storage]
  )

  const updateSession = useCallback(
    async (id: string, patch: Partial<Pick<AnnotSession, 'name' | 'status' | 'viewport' | 'note'>>) => {
      if (patch.name !== undefined && !patch.name.trim()) return
      try {
        const updated = await storage.updateSession(id, patch)
        setSessions((prev) => prev.map((s) => (s.id === id ? updated : s)))
      } catch (e) {
        console.error('[specbridge] updateSession failed', e)
      }
    },
    [storage]
  )

  const setSessionStatus = useCallback(
    async (id: string, status: SessionStatus) => {
      await updateSession(id, { status })
    },
    [updateSession]
  )

  const setSessionViewport = useCallback(
    async (id: string, viewport: SessionViewport | null) => {
      await updateSession(id, { viewport })
    },
    [updateSession]
  )

  const deleteSession = useCallback(
    async (id: string) => {
      try {
        await storage.deleteSession(id)
        const remaining = await storage.loadSessions()
        if (remaining.length === 0) {
          // 마지막 세션 삭제 시 기본 회차 자동 재생성
          const session = await storage.createSession('1차 검토')
          setSessions([session])
        } else {
          setSessions(remaining)
        }
      } catch (e) {
        console.error('[specbridge] deleteSession failed', e)
      }
    },
    [storage]
  )

  return { sessions, addSession, updateSession, setSessionStatus, setSessionViewport, deleteSession }
}
